namespace sv_bc55fc401f7a41f58ecd15ffe9d05171.Client;

// Serializable DTO used to persist auth state across render modes.
public sealed class UserInfo
{
    public required string Email { get; set; }
    public required string[] Roles { get; set; }
}

using System.Security.Claims;
using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Authorization;

namespace sv_bc55fc401f7a41f58ecd15ffe9d05171.Client;

// Client-side (WebAssembly) provider that reads the auth state
// persisted by the server during prerendering.
public sealed class PersistentAuthenticationStateProvider : AuthenticationStateProvider
{
    private static readonly Task<AuthenticationState> _unauthenticated =
        Task.FromResult(new AuthenticationState(new ClaimsPrincipal(new ClaimsIdentity())));

    private readonly Task<AuthenticationState> _authenticationStateTask;

    public PersistentAuthenticationStateProvider(PersistentComponentState state)
    {
        if (state.TryTakeFromJson<UserInfo>(nameof(UserInfo), out var userInfo) && userInfo is not null)
        {
            var claims = new List<Claim>
            {
                new(ClaimTypes.Name, userInfo.Email),
                new(ClaimTypes.Email, userInfo.Email),
            };

            foreach (var role in userInfo.Roles)
            {
                claims.Add(new Claim(ClaimTypes.Role, role));
            }

            var identity = new ClaimsIdentity(claims, authenticationType: nameof(PersistentAuthenticationStateProvider));
            _authenticationStateTask = Task.FromResult(new AuthenticationState(new ClaimsPrincipal(identity)));
        }
        else
        {
            _authenticationStateTask = _unauthenticated;
        }
    }

    public override Task<AuthenticationState> GetAuthenticationStateAsync() => _authenticationStateTask;
}

using System.Security.Claims;
using Microsoft.AspNetCore.Components.Authorization;

namespace sv_bc55fc401f7a41f58ecd15ffe9d05171.Auth;

// Server-side provider that simulates a logged-in user.
public sealed class ServerAuthenticationStateProvider : AuthenticationStateProvider
{
    private readonly Task<AuthenticationState> _authenticationState;

    public ServerAuthenticationStateProvider()
    {
        var claims = new[]
        {
            new Claim(ClaimTypes.Name, "bob@example.com"),
            new Claim(ClaimTypes.Email, "bob@example.com"),
            new Claim(ClaimTypes.Role, "User"),
            new Claim(ClaimTypes.Role, "Editor"),
        };

        var identity = new ClaimsIdentity(claims, authenticationType: "HardcodedAuth");
        _authenticationState = Task.FromResult(new AuthenticationState(new ClaimsPrincipal(identity)));
    }

    public override Task<AuthenticationState> GetAuthenticationStateAsync() => _authenticationState;
}

using System.Security.Claims;
using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Authorization;
using Microsoft.AspNetCore.Components.Web;
using sv_bc55fc401f7a41f58ecd15ffe9d05171.Client;

namespace sv_bc55fc401f7a41f58ecd15ffe9d05171.Auth;

// Subscribes to auth state changes during server-side prerendering and
// serializes the user info into PersistentComponentState so the
// WebAssembly runtime can pick it up without another round-trip.
public sealed class PersistingServerAuthenticationStateProvider : IDisposable
{
    private readonly PersistentComponentState _state;
    private readonly AuthenticationStateProvider _authStateProvider;
    private PersistingComponentStateSubscription _subscription;

    public PersistingServerAuthenticationStateProvider(
        PersistentComponentState state,
        AuthenticationStateProvider authStateProvider)
    {
        _state = state;
        _authStateProvider = authStateProvider;
        _subscription = state.RegisterOnPersisting(OnPersistingAsync, RenderMode.InteractiveWebAssembly);
    }

    private async Task OnPersistingAsync()
    {
        var authState = await _authStateProvider.GetAuthenticationStateAsync();
        var principal = authState.User;

        if (principal.Identity?.IsAuthenticated == true)
        {
            var userInfo = new UserInfo
            {
                Email = principal.FindFirst(ClaimTypes.Email)?.Value
                        ?? principal.Identity.Name
                        ?? string.Empty,
                Roles = principal.FindAll(ClaimTypes.Role).Select(c => c.Value).ToArray(),
            };

            _state.PersistAsJson(nameof(UserInfo), userInfo);
        }
    }

    public void Dispose() => _subscription.Dispose();
}

