+namespace sv_bc55fc401f7a41f58ecd15ffe9d05171.Auth;
+
+// Subscribes to auth state changes during server-side prerendering and
+// serializes the user info into PersistentComponentState so the
+// WebAssembly runtime can pick it up without another round-trip.
+public sealed class PersistingServerAuthenticationStateProvider : IDisposable
+{
+    private readonly PersistentComponentState _state;
+    private readonly AuthenticationStateProvider _authStateProvider;
+    private readonly PersistingComponentStateSubscription _subscription;
+
+    public PersistingServerAuthenticationStateProvider(
+        PersistentComponentState state,
+        AuthenticationStateProvider authStateProvider)
+    {
+        _state = state;
+        _authStateProvider = authStateProvider;
+        _subscription = state.RegisterOnPersisting(OnPersistingAsync, RenderMode.InteractiveWebAssembly);
+    }
+
+    private async Task OnPersistingAsync()
+    {
+        var authState = await _authStateProvider.GetAuthenticationStateAsync();
+        var principal = authState.User;
+
+        if (principal.Identity?.IsAuthenticated == true)
+        {
+            var userInfo = new UserInfo
+            {
+                Email = principal.FindFirst(ClaimTypes.Email)?.Value
+                        ?? principal.Identity.Name
+                        ?? string.Empty,
+                Roles = principal.FindAll(ClaimTypes.Role).Select(c => c.Value).ToArray(),
+            };
+
+            _state.PersistAsJson(nameof(UserInfo), userInfo);
+        }
+    }
