using System.Security.Claims;
using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Authorization;
using Microsoft.AspNetCore.Components.Web;
using sv_bc55fc401f7a41f58ecd15ffe9d05171.Client;

namespace sv_bc55fc401f7a41f58ecd15ffe9d05171.Auth;

// Server-side provider that simulates a logged-in user and persists
// auth state into PersistentComponentState for the WebAssembly runtime.
public sealed class ServerAuthenticationStateProvider : AuthenticationStateProvider, IDisposable
{
    private readonly Task<AuthenticationState> _authenticationState;
    private readonly PersistingComponentStateSubscription _subscription;

    public ServerAuthenticationStateProvider(PersistentComponentState persistentState)
    {
        var claims = new[]
        {
            new Claim(ClaimTypes.Name, "bob@example.com"),
            new Claim(ClaimTypes.Email, "bob@example.com"),
            new Claim(ClaimTypes.Role, "User"),
            new Claim(ClaimTypes.Role, "Editor"),
        };

        var identity = new ClaimsIdentity(claims, authenticationType: "HardcodedAuth");
        _authenticationState = Task.FromResult(new AuthenticationState(new ClaimsPrincipal(identity)));

        _subscription = persistentState.RegisterOnPersisting(() =>
        {
            persistentState.PersistAsJson(nameof(UserInfo), new UserInfo
            {
                Email = "bob@example.com",
                Roles = new[] { "User", "Editor" },
            });
            return Task.CompletedTask;
        }, RenderMode.InteractiveWebAssembly);
    }

    public override Task<AuthenticationState> GetAuthenticationStateAsync() => _authenticationState;

    public void Dispose() => _subscription.Dispose();
}

